	
SELECT * FROM customer LIMIT 5;

--Question 1. What is the total revenue generated by male versus female customer?
SELECT Gender, SUM (purchase_amount) AS revenue
FROM customer
GROUP BY gender

--Question 2. Which customers used a discount but still spent more than the average purchase amount? 
SELECT customer_id , purchase_amount 
FROM customer
WHERE discount_applied = 'Yes' and purchase_amount >= (SELECT AVG(purchase_amount) FROM customer)

--Question 3. Which are the top five products with the highest average review rating? 
